    59|  const primary: IVXProviderStatus = {
    60|    name: 'vercel_ai_gateway',
    61|    role: 'primary',
    62|    configured: hasEnv('AI_GATEWAY_API_KEY'),
    63|    envGates: ['AI_GATEWAY_API_KEY'],
