    86|/** Map a thrown gateway error into a coarse class. */
    87|export function classifyProviderFailure(error: unknown): IVXProviderFailureClass {
    88|  if (!error) return 'unknown';
    89|  const name = error instanceof Error ? error.name : '';
    90|  const message = error instanceof Error ? error.message.toLowerCase() : String(error).toLowerCase();
